#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y; scanf("%d %d", &X, &Y);
        if (Y > X) printf("PROFIT\n");
        else if (Y < X) printf("LOSS\n");
        else printf("NEUTRAL\n");
    }
    return 0;
}

